mapper.select:
SELECT task_id, repair_type, user_id, dedupe_key, status, retry_count, claim_owner, claimed_at, lease_until, next_retry_time, reason, last_error, create_time, update_time FROM class2_user_counter_repair_task WHERE task_id IN
#{taskId}
ORDER BY task_id ASC

mapper.update:
UPDATE class2_user_counter_repair_task
SET status = 'DONE',
    claim_owner = NULL,
    claimed_at = NULL,
    lease_until = NULL,
    update_time = #{updateTime}
WHERE task_id = #{taskId}
  AND claim_owner = #{owner}

UPDATE class2_user_counter_repair_task
SET status = 'PENDING',
    claim_owner = NULL,
    claimed_at = NULL,
    lease_until = NULL,
    next_retry_time = #{nextRetryTime},
    reason = #{reason},
    update_time = #{updateTime}
WHERE task_id = #{taskId}
  AND claim_owner = #{owner}
